import os
import json
import requests
import hashlib
from datetime import datetime

class APICache:
    def __init__(self, cache_dir='api_cache'):
        self.cache_dir = cache_dir
        if not os.path.exists(self.cache_dir):
            os.makedirs(self.cache_dir)

    def _get_cache_path(self, endpoint, params):
        params_string = json.dumps(params, sort_keys=True)
        params_hash = hashlib.md5(params_string.encode()).hexdigest()
        return os.path.join(self.cache_dir, f'{endpoint.replace("/", "_")}_{params_hash}.json')

    def request(self, endpoint, params):
        cache_path = self._get_cache_path(endpoint, params)
        if os.path.exists(cache_path):
            with open(cache_path, 'r') as cache_file:
                cache_data = json.load(cache_file)
                if datetime.now().timestamp() - cache_data['timestamp'] < 3600:  # 1 hour cache
                    return cache_data['response']

        response = requests.get(endpoint, params=params).json()

        with open(cache_path, 'w') as cache_file:
            json.dump({
                'timestamp': datetime.now().timestamp(),
                'response': response
            }, cache_file)

        return response